import{$ as e,A as t,B as n,V as r}from"./chunks/framework.6NwDR3kH.js";var i=JSON.parse(`{"title":"散热","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/电脑/散热.md","filePath":"ccc/电脑/散热.md"}`),a={name:`ccc/电脑/散热.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="散热" tabindex="-1">散热 <a class="header-anchor" href="#散热" aria-label="Permalink to “散热”">​</a></h1><h2 id="风冷散热器" tabindex="-1">风冷散热器 <a class="header-anchor" href="#风冷散热器" aria-label="Permalink to “风冷散热器”">​</a></h2><p>  侧吹相对下压cpu散热能力通常更强，但是下压能吹到主板供电。主板供电能力远超cpu，选侧吹。主板小马拉大车，裸奔，ITX，选下压吹供电。</p><ul><li><strong>雅俊b3</strong><code>89</code></li></ul><blockquote><p>  最佳中低端侧吹之一，30度室温都能压120wPL1。另售IFE2防拔出支架，防止把AM4-cpu拔出来。</p></blockquote><ul><li>超频三 七星瓢虫 v5 <code>45</code></li></ul><blockquote><p>  入门下压，双热管。</p></blockquote><ul><li>利民pa120/fs140 <code>199</code></li></ul><blockquote><p>  fs140镜面铜底，更适合英特尔平台。pa120热压直触更适合amd锐龙平台。</p></blockquote><h2 id="硅脂" tabindex="-1">硅脂 <a class="header-anchor" href="#硅脂" aria-label="Permalink to “硅脂”">​</a></h2><p>裸die，如显卡，笔记本等推荐用霍尼韦尔7950相变导热片，性能一般，但是永远不会干，die在微观下凹凸不平，笔记本往往温度要80度以上，硅油易挥发，容易产生空隙。由于都是商家分装，我个人觉得不如拼多多买几块包邮的，100%是国产的，性能差距不特别大，买更贵的也不一定就不是国产的。</p><ul><li>顶级硅脂：雅浚W15 II，利民TF7，TFX等，九州风神DM9等，</li></ul><blockquote><p>性能都非常强，但是耐久性较差。</p></blockquote><p>信越7921非常难涂；性能比顶级硅脂差一档，但是耐久性强很多，散装的都是商家分装，真假无从分辨，可以考虑利民tf4，贴牌7921。掺硅油的7868更好涂，但是要等几天硅油挥发才能完全发挥性能，耐久性会差一些。</p><ul><li><p>华能智研HY880效果略逊于7921，但是便宜保真。<a href="https://link.zhihu.com/?target=https%3A//item.taobao.com/item.htm%3Fspm%3Da21n57.1.0.0.7495523cNqYKls%26id%3D553223110001%26ns%3D1%26abbucket%3D0%23detail" target="_blank" rel="noreferrer">16.8￥包邮30g</a>。</p></li><li><p>高导gd2在一些测试中效果比7921好，但是有磨花顶盖的议论。</p></li><li><p>hy883是hy880加硅油，稀一点；高导gd900更稀，<a href="https://link.zhihu.com/?target=https%3A//item.taobao.com/item.htm%3Fspm%3Da1z0k.7386009.0.d4919233.5b8537deRNGccr%26id%3D40666449492%26_u%3Dt2dmg8j26111" target="_blank" rel="noreferrer">6块多不包邮30g</a>。<strong>3~6个月一换可以用稀的。</strong></p></li></ul><blockquote><p>我推测加硅油更稀的硅脂，可能压平摊的更薄，硅油挥发一部分后，效果反而更好，但是不耐久。</p></blockquote><h2 id="机箱风扇" tabindex="-1">机箱风扇 <a class="header-anchor" href="#机箱风扇" aria-label="Permalink to “机箱风扇”">​</a></h2><p>机箱风扇如果懒得研究，可以考虑鑫谷飞逸，价格实惠，带D型供电接头可以接电源，噪音也很轻。</p><p>十几块包邮的风扇，尽量挑有2~3年售后的买，这类风扇包括鑫谷飞逸，往往故障率较高，可能一两年就坏了或者出现异响，偏振等问题。</p><ul><li><p><strong>风扇方向</strong>：通常风扇从没有挡板支架的一面吹向有挡板支架的一面。</p></li><li><p><strong>风压与风量</strong></p></li></ul><p>风量既气体交换量，风压既产生的压力，通常大风压风扇更贵，我的体感是大风压风扇在相近转速下有更明显的风噪。</p><p>厂家标称的往往是最大风量或最大风压。举例来说，在空旷环境下风压越大的风扇，风能吹到的距离就越远，在吹不到的距离下，无论风扇的最大风量有多大，其风量=0。</p><p>通常cpu散热器，冷排需要大风压风扇，不然吹不透。</p><ul><li><strong>正压与负压</strong></li></ul><p>从外向内吹的会形成正压，通常机箱会给进气风扇设计防尘滤网。</p><p>从内往外吹的会形成负压。</p><p>一旦负压大于正压，气体就会从各种缝隙进入，反之正压大于负压，则气体会从各种缝隙流出。所以要尽量避免机箱形成负压环境，会导致缝隙沾染灰尘。</p><p>上盖封闭的闷罐机箱，既主打静音防尘的机箱，不需要大风压风扇，正面2~3个进气风扇，背面1个出风风扇一般能形成正压。</p><p>大量开孔，主打散热的机箱，进气风扇如果不是大风压风扇，往往会在出气风扇附近形成局部负压，周围的缝隙沾染灰尘。</p><ul><li><p>不考虑扇叶设计等优化，通常尺寸越大，达到相同风量风压的转速越低。</p></li><li><p>12~14cm风扇在1200rpm转速下比较静音。</p></li><li><p>进气风扇装3把14cm风扇，一般需要全塔机箱，既高度在500mm左右的机箱。中塔机箱，既高度在470mm左右的，如果要装3把风扇，建议12cm，虽然机箱厂家会标注支持3把14cm，但是装起来很局促。</p></li><li><p><strong>电源接口</strong></p></li></ul><p>D型电源接口都是连电源，满速运行。4pin接口一般支持pwm与dc调速，而2pin或3pin一般支持DC调速，3pin第三脚一般用于检测转速。</p><ul><li><strong>pwm调速与dc调速</strong></li></ul><p>dc调速既通过降低电压来降速，而pwm则保持12V供电，但是供电时断时续来实现调速。</p><p>理论上pwm调速可以实现一个更慢的转速，dc调速往往电压低到拐点直接停转了，如果风扇的LED是从风扇取电，可能更容易停转。但还是要自行测试，也有dc调速反而能比pwm调速转的更慢的风扇。</p><ul><li><strong>环境温度与温升</strong></li></ul><p>假设室温26度，100w功耗下，cpu温度达到76度，既温升50度，在室温6度的情况下，保持同样的100w功耗，排除风扇调速，自动睿频，温度墙功耗墙等，温升同样还是50度，cpu温度会是56度。</p><h3 id="机箱风扇推荐" tabindex="-1">机箱风扇推荐 <a class="header-anchor" href="#机箱风扇推荐" aria-label="Permalink to “机箱风扇推荐”">​</a></h3><p>如果不想折腾风扇调速配置，可以考虑Arctic的风扇，就算主板预设100%转速，也很安静。</p><p>我强烈推荐追风者风扇，性能不错，性价比也可以。追风者sk神风大风量小风压，m25有一定风压，可以吹冷排散热器，f140mp风压更大，零售mp2优化了细节，拆机版mp1则价格实惠。</p><h3 id="风扇策略设置" tabindex="-1">风扇策略设置 <a class="header-anchor" href="#风扇策略设置" aria-label="Permalink to “风扇策略设置”">​</a></h3><p>风扇策略的配置离不开主板设计，如果想要对风扇进行个性化配置，先要确认主板有几个系统风扇接口。</p><p>微星bios预设机箱风扇不能调速，满速运转，需要自行调整设置，</p><p>华硕bios预设风扇可调速并加载默认调速配置。</p><p>微星在bios下调整风扇设置的体验非常好，windows软件则非常拉跨。</p><p>华硕提供自动测试最低转速占空比的功能，bios下调整体验较差，windows软件体验好得多。</p><p><strong>以下是我个人经验，并非标准做法：</strong></p><p>将风扇策略的两个节点拉成一条直线，对准当前温度，找风扇最低转速，听不到噪音的最高转速，噪音可以接受的最大转速。</p><p>例1：先马朱雀air，开孔多，正面2x追风者m25-14cm，背面1x神风sk。</p><p>追风者m25，最低转速14%，几乎无噪音40%，70%以上噪音偏大。</p><p>神风sk，最低转速8%，几乎无噪音60%，80%以上噪音偏大。</p><p>负压风扇在cpu40度以下停转，40度开始加速到70度80%，75度100%。</p><p>cpu半区的正压风扇在40度以下保持最低转速，逐渐加速到40度，40%转速，保持转速到65度，</p><p>显卡半区的正压风扇策略根据室温经常调整，显卡无温升就保持最低转速，有3度以上温升，有负载直接40%转速，加速到20度温升70%转速，30度温升后100%转速。显卡是铭瑄电竞之心，核心散热非常好，但是显存散热不是特别理想，gpu温升很小，满载也才30度不到。</p><p>例2：航嘉阿尔法，闷罐，正面3x追风者m25-14cm，背面1x神风sk。</p><p>装满硬盘，为了避免吹不透硬盘笼，正面选择了有一定风压的风扇。cpu满载也才65w，主板八相drmos，mos有散热片，散热器也是下压散热器，负压风扇40度以下停转，加速到70度90%转速，75度100%转速。</p><p>正压风扇25度以下最低转速，35度30%，75度50%，之后100%。</p><p>cpu风扇40度以下最低转速，70度50%，75度100%。</p><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to “参考链接”">​</a></h2><p><a href="https://www.expreview.com/77958.html" target="_blank" rel="noreferrer">热管性能会随着时间推移下降</a></p>`,59)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};